    ('SEAS-B 101', 'ELEMENTARY BURMESE I', '10752', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'WH 111', 'Kaung Myat', 6, NULL, 'Practice', '4', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Introductory course in Burmese emphasizing listening and speaking in simple interpersonal interactions, as well as basic reading and writing skills.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SEAS-B 201', 'INTERMEDIATE BURMESE I', '14095', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'BH 233', 'Kaung Myat', 8, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Focuses on listening, speaking, reading and writing in Burmese. Introduces early to mid-intermediate level Burmese language vocabulary and grammar.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SEAS-B 201', 'INTERMEDIATE BURMESE I', '34623', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Kaung Myat', 4, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Focuses on listening, speaking, reading and writing in Burmese. Introduces early to mid-intermediate level Burmese language vocabulary and grammar.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SEAS-F 101', 'ELEMENTARY TAGALOG I', '14532', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'LH 112', 'Jemerson Eugenio', 3, NULL, 'Lecture', '4', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Introductory skills-oriented course emphasizing learning Tagalog in context. Development of listening and speaking in simple interactional situations, and controlled reading and writing skills.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SEAS-F 201', 'INTERMEDIATE TAGALOG I', '29291', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'PY 115', 'Jemerson Eugenio', 11, NULL, 'Lecture', '4', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Prepares students to use Tagalog (Filipino) for various communicative purposes at the intermediate level: to converse with ease and confidence when dealing with some routine tasks and social situations, and to comprehend and produce some compositions about everyday events and experiences.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SEAS-S 761', 'INDEPENDENT READING/RESEARCH IN SOUTHEAST ASIAN AND ASEAN STUDIES', '8088', 'Class Status', NULL, NULL, 'Jennifer Goodlander', 5, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], 'Independent supervised reading and/or research and creative activity that synthesizes existing scholarship and/or generates new insights into study of Southeast Asia. Supervised by a faculty member upon approval by the Program.', ARRAY[]::TEXT[], NULL),
    ('SEAS-T 101', 'ELEMENTARY THAI I', '9767', 'Class Status', 'MWF Monday, Wednesday, Friday 8:00 AM–8:50 AM', 'BH 219', 'Peerapat Muangklan', 3, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'An introductory course emphasizing speaking, listening, reading, and writing skills in relation to Thai consonants, vowels, and tones; comprehension and production of simple and compound sentences; and use of Thai for simple functional purposes.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SEAS-T 201', 'INTERMEDIATE THAI I', '8913', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'ED 3004', 'Peerapat Muangklan', 2, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Continuation of SEAS-T 102. Focuses on Thai grammar, conversation, vocabulary, and written language. Provides practice in reading authentic materials such as newspapers and becoming proficient at short conversations.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SEAS-T 501', 'ELEMENTARY THAI I', '9768', 'Class Status', 'MWF Monday, Wednesday, Friday 8:00 AM–8:50 AM', 'BH 219', 'Peerapat Muangklan', 3, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introductory course emphasizing Thai tones and consonant/vowel sounds, complex spelling rules, reading and production of compound and complex sentences, and vocabulary development.', ARRAY[]::TEXT[], NULL),
