    ('SGIS-X 573', 'INTERNSHIP/PRACTICUM IN GLOBAL AND INTERNATIONAL STUDIES', '34895', 'Class Status', 'M Monday 4:45 PM–6:00 PM', 'WB WEB', 'Siddharth Bose, Isak Nti Asare, Scott Shackelford', 7, NULL, 'Internship', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'SGIS X573 provides academic structure to graduate students who wish to participate in an in-depth internship or practicum experience, domestically or internationally. Students complete the internship/practicum under the supervision of an approved agency field supervisor and academic guidance of a faculty member with substantial knowledge of the topic.', ARRAY[]::TEXT[], NULL),
