    ('SGIS-X 573', 'INTERNSHIP/PRACTICUM IN GLOBAL AND INTERNATIONAL STUDIES', '37565', 'Class Status', NULL, NULL, 'Katherine Ntiamoah', 12, NULL, 'Internship', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'SGIS X573 provides academic structure to graduate students who wish to participate in an in-depth internship or practicum experience, domestically or internationally. Students complete the internship/practicum under the supervision of an approved agency field supervisor and academic guidance of a faculty member with substantial knowledge of the topic.', ARRAY[]::TEXT[], NULL),
    ('SICE-Y 100', 'EXPLORING TECH PATHWAYS', '6134', 'Class Status', 'Tu Tuesday 2:20 PM–3:35 PM', 'PV A221', 'Anna Bednarski', 6, NULL, 'Lecture', '1', 'SPEA', ARRAY[]::TEXT[], 'Technology is everywhere, and how it relates to the world today is very important to the future. This interactive course will offer students the opportunity to explore the many academic / career pathways available specifically through Luddy, as well as within the broader technology workforce, with a focus on self-reflection.', ARRAY[]::TEXT[], NULL),
    ('SICE-Y 100', 'EXPLORING TECH PATHWAYS', '34135', 'Class Status', 'Tu Tuesday 2:20 PM–3:35 PM', 'PV A221', 'Shamim Ali', 19, NULL, 'Lecture', '1', 'SPEA', ARRAY[]::TEXT[], 'Technology is everywhere, and how it relates to the world today is very important to the future. This interactive course will offer students the opportunity to explore the many academic / career pathways available specifically through Luddy, as well as within the broader technology workforce, with a focus on self-reflection.', ARRAY[]::TEXT[], NULL),
