    ('SLAV-G 599', 'THESIS RESEARCH', '3132', 'Class Status', NULL, NULL, 'George Fowler', 2, NULL, 'Independent Study', '0', NULL, ARRAY[]::TEXT[], 'Master''s students who have enrolled in 30 or more hours of graduate course work applicable to the degree and who have completed all other requirements of the degree except the thesis of final project of performance may enroll in G599. Requires section authorization.', ARRAY[]::TEXT[], NULL),
    ('SLAV-G 901', 'ADVANCED RESEARCH', '2942', 'Class Status', NULL, NULL, 'George Fowler', 9, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('SLAV-L 505', 'STRUCTURE AND HISTORY OF A SLAVIC LANGUAGE: VARIABLE TITLE', '29764', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 231', 'Malgorzata Cavar', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Synchronic and diachronic analysis of a single Slavic language (usually of language not regularly taught in department), including developmental trends and dialects. Will attempt to provide rapid facility for reading texts (especially linguistic), by building on student''s knowledge of Russian.', ARRAY[]::TEXT[], NULL),
    ('SLAV-L 555', 'SLAVIC TOPICS IN APPLIED LINGUISTICS', '36658', 'Closed', NULL, NULL, 'Rebecca Cravens', 0, NULL, 'Readings', '1–3', NULL, ARRAY[]::TEXT[], 'Graduate level work on topics in applied linguistics in Slavic studies, for example language pedagogy, language assessment, computational linguistics, or a teaching methods practicum.', ARRAY[]::TEXT[], NULL),
