    ('SLAV-P 565', 'SEM POLISH LIT & CULTURE:V.T', '33755', 'Class Status', 'M Monday 3:55 PM–6:25 PM', 'BH 229', 'Lukasz Sicinski', 7, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Intensive study of an author, a period, or a literary or cultural development. Research papers required.', ARRAY[]::TEXT[], NULL),
    ('SLAV-R 101', 'ELEMENTARY RUSSIAN I', '2949', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 10:25 AM–11:15 AM', 'BH 241', 'Maria Shardakova, Rebecca Cravens', 8, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduction to contemporary Russian and aspects of Russian culture. Intensive drill and exercises in basic structure; development of vocabulary.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SLAV-R 101', 'ELEMENTARY RUSSIAN I', '2950', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 11:35 AM–12:25 PM', 'BH 229', 'Maria Shardakova, Alexandra Puccio', 4, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduction to contemporary Russian and aspects of Russian culture. Intensive drill and exercises in basic structure; development of vocabulary.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SLAV-R 101', 'ELEMENTARY RUSSIAN I', '2951', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 12:45 PM–1:35 PM', 'BH 229', 'Maria Shardakova, Rebecca Cravens', 2, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduction to contemporary Russian and aspects of Russian culture. Intensive drill and exercises in basic structure; development of vocabulary.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SLAV-R 101', 'ELEMENTARY RUSSIAN I', '9437', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 1:55 PM–2:45 PM', 'BH 241', 'Maria Shardakova, Selim Kim', 10, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduction to contemporary Russian and aspects of Russian culture. Intensive drill and exercises in basic structure; development of vocabulary.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SLAV-R 201', 'INTERMEDIATE RUSSIAN I', '4020', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 11:35 AM–12:25 PM', 'BH 241', 'Maria Shardakova, Sofiya Asher', 1, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Continuation of work in structure and vocabulary acquisition through study of grammar, drills, and readings. Oral practice and written exercises.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SLAV-R 201', 'INTERMEDIATE RUSSIAN I', '4210', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 10:25 AM–11:15 AM', 'BH 142', 'Maria Shardakova, Sabina Iusupova', 7, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Continuation of work in structure and vocabulary acquisition through study of grammar, drills, and readings. Oral practice and written exercises.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SLAV-R 223', 'INTRODUCTION TO RUSSIAN CULTURE', '2952', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'LH 135', 'Elizabeth Geballe', 0, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Survey of the development of Russian culture and thought from Medieval Russia to the Soviet Union today, as seen primarily through literature and the arts. No knowledge of Russian necessary.', ARRAY['IUB GenEd A&H credit
IUB GenEd World Culture credit
COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('SLAV-R 229', 'RUSSIAN FOLK TALES', '37338', 'Closed', NULL, 'WB WEB', 'Miriam Shrager', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Survey, analysis, and origins of traditional Russian Folk tales based on thematic and structural classifications. Various approaches and theories are introduced in analyzing and interpreting folk tales, e.g., structural, formalist, thematic, and psychological. Pagan mythology, customs, and rituals are viewed as the possible origins of folktales. Influence of folk tales in music, arts, and cinema.', ARRAY['IUB GenEd A&H credit
IUB GenEd World Culture credit
COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('SLAV-R 263', 'RUS LIT: PUSHKIN TO DOSTOEVSKY', '2953', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'LH 135', 'Elizabeth Geballe', 0, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'The Golden Age of the Russian Novel; its social, cultural, and economic context; the flowering of art and music; the rise of the metropolis in associations with poverty, alienation, quest for identity (both national and personal), as reflected in the Romantic and Realistic works of Pushkin, Gogol, Turgenev, and Dostoevsky. Knowledge of Russian not required.', ARRAY['IUB GenEd A&H credit
IUB GenEd World Culture credit
COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('SLAV-R 301', 'ADVANCED INTERMEDIATE RUSSIAN I', '5195', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'GA 0011', 'Svitlana Melnyk', 7, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Morphological, lexical, and syntactic analysis of a broad spectrum of textual materials with special emphasis on meaning. Development of oral and written fluency and comprehension. Remedial grammar and phonetics as required.', ARRAY[]::TEXT[], NULL),
    ('SLAV-R 366', 'RUSSIAN AND SOVIET FILM', '8327', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'LH 125', 'Miriam Shrager', 14, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Development of Russian cinematography from 1896 to the present. Characteristic features of Soviet films; the theory and practice of filmmaking in the former Soviet Union; the Soviet and Russian cinema in its relationship to Russian literature and in the larger context of European cinema art. Knowledge of Russian not required.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('SLAV-R 398', 'SPECIAL CREDIT IN SLAVIC LANGUAGES', '2954', 'Class Status', NULL, NULL, 'George Fowler', 10, NULL, 'Lecture', '1–3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SLAV-R 401', 'ADVANCED RUSSIAN I', '14622', 'Class Status', 'MWF Monday, Wednesday, Friday 1:55 PM–2:45 PM', 'GA 0011', 'Gulshat Safiullina, Maria Shardakova', 13, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Refinement of active and passive language skills, with emphasis on vocabulary building and word usage. Extensive reading, discussion, composition writing. Individualized remedial drill in grammar and pronunciation aimed at preparing students to meet departmental language proficiency standards.', ARRAY[]::TEXT[], NULL),
    ('SLAV-R 421', 'FIFTH-YEAR RUSSIAN', '32912', 'Class Status', 'MWF Monday, Wednesday, Friday 3:10 PM–4:00 PM', 'BH 241', 'Svitlana Melnyk', 5, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This course continues developing students'' advanced skills in Russian, while focusing on a particular topic related to a diverse range of social, cultural, or historical domains. Language work includes writing, syntactical and stylistic analysis, academic speech, reading and listening activities.', ARRAY[]::TEXT[], NULL),
    ('SLAV-R 425', 'ADVANCED ORAL RUSSIAN I', '9442', 'Class Status', 'W Wednesday 4:20 PM–5:10 PM', 'PV 270', 'Maria Shardakova', 6, NULL, 'Lecture', '1', 'SPEA', ARRAY[]::TEXT[], 'Designed primarily for those interested in maintaining or developing oral fluency. Sections in advanced conversation, recitation and oral comprehension, dictation, and reading.', ARRAY[]::TEXT[], NULL),
    ('SLAV-R 501', 'FIFTH YEAR RUSSIAN', '33745', 'Class Status', 'MWF Monday, Wednesday, Friday 3:10 PM–4:00 PM', 'BH 241', 'Svitlana Melnyk', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This course continues developing students'' advanced skills in Russian, while focusing on a particular topic related to a diverse range of social, cultural, or historical domains. Language work includes writing, syntactical and stylistic analysis, academic speech, reading and listening activities.', ARRAY[]::TEXT[], NULL),
    ('SLAV-R 550', 'RUSSIAN DRAMA', '29492', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'TH A300', 'Russell Valentino', 4, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SLAV-R 552', 'RUSSIAN AND SOVIET FILM', '8595', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'LH 125', 'Miriam Shrager', 14, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SLAV-R 563', 'PUSHKIN TO DOSTOEVSKY', '2955', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'LH 135', 'Elizabeth Geballe', 2, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SLAV-S 101', 'ELEMENTARY BOSNIAN/CROATIAN/SERBIAN I', '2956', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 9:10 AM–10:00 AM', 'IF 0002', 'Julija Pesic, Teuta Ozcelik', 9, NULL, 'Lecture', '4', 'LUDDY HALL', ARRAY[]::TEXT[], 'No previous knowledge of Bosnian, Croatian, or Serbian required. Introduction to all four language skills: listening, reading, speaking, and writing. Surveys the cultures of Bosnia and Herzegovina, Croatia, Montenegro, and Serbia.', ARRAY['IUB GenEd World Language class'], NULL),
