    ('SLAV-S 301', 'ADVANCED INTERMEDIATE BOSNIAN/CROATIAN/SERBIAN I', '2957', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'GA 4021', 'Julija Pesic, Teuta Ozcelik', 6, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Morphological, lexical, and syntactic analysis of a broad spectrum of textual materials with special emphasis on meaning. Development of oral and written fluency and comprehension. Remedial grammar and phonetics as required.', ARRAY[]::TEXT[], NULL),
