    ('SLAV-S 320', 'SPECIAL TOPICS IN SLAVIC STUDIES', '32816', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'BH 145', 'Russell Valentino', 14, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Study and analysis of literary and cultural issues and problems in the Slavic studies area. Variable topics ranging from a study of a single novel or genre to selected themes of Slavic literature in their historical and cultural contexts. Topics will vary from semester to semester.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('SLAV-S 320', 'SPECIAL TOPICS IN SLAVIC STUDIES', '30128', 'Closed', 'Tu Tuesday 5:30 PM–6:20 PM', 'BH 105', 'Jeffrey Holdeman', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Study and analysis of literary and cultural issues and problems in the Slavic studies area. Variable topics ranging from a study of a single novel or genre to selected themes of Slavic literature in their historical and cultural contexts. Topics will vary from semester to semester.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('SLAV-S 363', 'LIT & CULTURE SOUTH SLAVS I: LITERATURE AND NATIONALISM IN THE BALKANS', '30132', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'JH 440', 'Nicoletta Rousseva', 11, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Survey of literary and intellectual history of the South Slavs in the late 19th and early 20th centuries, with a special focus on the foundational ideology of nations and nationalism in this period. Readings and discussions in English.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('SLAV-S 501', 'ELEMENTARY BOSNIAN/CROATIAN/SERBIAN I', '15321', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 9:10 AM–10:00 AM', 'IF 0002', 'Julija Pesic, Teuta Ozcelik', 2, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'In this class, you will learn the Croatian/Serbian/Bosnian language at the elementary level, as well as its culture. We will travel across all the former Yugoslavian countries (e.g. Croatia, Bosnia and Herzegovina, Serbia, Montenegro, Slovenia, North Macedonia, Kosovo), and learn about the language & culture.', ARRAY[]::TEXT[], NULL),
    ('SLAV-S 501', 'ELEMENTARY BOSNIAN/CROATIAN/SERBIAN I', '2959', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 9:10 AM–10:00 AM', 'WB WEB', 'Julija Pesic, Teuta Ozcelik', 5, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'In this class, you will learn the Croatian/Serbian/Bosnian language at the elementary level, as well as its culture. We will travel across all the former Yugoslavian countries (e.g. Croatia, Bosnia and Herzegovina, Serbia, Montenegro, Slovenia, North Macedonia, Kosovo), and learn about the language & culture.', ARRAY[]::TEXT[], NULL),
    ('SLAV-S 503', 'INTERMEDIATE BOSNIAN/CROATIAN/SERBIAN I', '13176', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'GY 4069', 'Julija Pesic, Teuta Ozcelik', 4, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'In this class, you will learn the Croatian/Serbian/Bosnian language at the intermediate level, as well as its culture. We will travel across all the former Yugoslavian countries (e.g. Croatia, Bosnia and Herzegovina, Serbia, Montenegro, Slovenia, North Macedonia, Kosovo), and learn the language & culture.', ARRAY[]::TEXT[], NULL),
    ('SLAV-S 503', 'INTERMEDIATE BOSNIAN/CROATIAN/SERBIAN I', '13177', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'WB WEB', 'Teuta Ozcelik, Julija Pesic', 5, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'In this class, you will learn the Croatian/Serbian/Bosnian language at the intermediate level, as well as its culture. We will travel across all the former Yugoslavian countries (e.g. Croatia, Bosnia and Herzegovina, Serbia, Montenegro, Slovenia, North Macedonia, Kosovo), and learn the language & culture.', ARRAY[]::TEXT[], NULL),
    ('SLAV-S 505', 'ADVANCED INTERMEDIATE BOSNIAN/CROATIAN/SERBIAN I', '2960', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'GA 4021', 'Julija Pesic, Teuta Ozcelik', 5, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Reading of literary texts from a variety of periods and locations in the Bosnian-Croatian-Serbian speech area. Sequence of readings in original parallels syllabus of S363-S364 in translation. Review of grammar, syntax and expansion of lexicon as needed.', ARRAY[]::TEXT[], NULL),
    ('SLAV-S 505', 'ADVANCED INTERMEDIATE BOSNIAN/CROATIAN/SERBIAN I', '8030', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'WB WEB', 'Staff', 2, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Reading of literary texts from a variety of periods and locations in the Bosnian-Croatian-Serbian speech area. Sequence of readings in original parallels syllabus of S363-S364 in translation. Review of grammar, syntax and expansion of lexicon as needed.', ARRAY[]::TEXT[], NULL),
