    ('SLAV-S 563', 'LIT&CULTR OF SOUTHERN SLAVS 1', '30371', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'JH 440', 'Nicoletta Rousseva', 6, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Survey of the cultures of the Slovenes, Croats, Serbs, Macedonians and Bulgarians from earliest times to the present. Reading and discussion of their major literary works in translation.', ARRAY[]::TEXT[], NULL),
