    ('SLAV-T 404', 'THE STRUCTURE OF THE SLAVIC LANGUAGES', '36828', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 231', 'Malgorzata Cavar', 10, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'The course covers topics in Slavic synchronic linguistics. Starting with peculiarities of word structure (morphology), over the articulation of sounds of speech (phonetics), and phonological effects, and ending with issues in syntax, we will show how the related languages select different strategies to deal with problematic linguistic structures.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('SLAV-T 499', 'SENIOR HONORS THESIS', '2958', 'Class Status', NULL, NULL, 'George Fowler, Jeffrey Holdeman', 10, NULL, 'Seminar', '1–6', NULL, ARRAY[]::TEXT[], 'Students write a departmental honors thesis (or similarly advanced, ambitious work to fulfill departmental honors, such as a substantial translation into English from a departmental language) under the guidance of a departmental faculty member.', ARRAY[]::TEXT[], NULL),
    ('SLAV-T 499', 'SENIOR HONORS THESIS', '15198', 'Closed', NULL, NULL, 'Elizabeth Geballe', 0, NULL, 'Seminar', '1–6', NULL, ARRAY[]::TEXT[], 'Students write a departmental honors thesis (or similarly advanced, ambitious work to fulfill departmental honors, such as a substantial translation into English from a departmental language) under the guidance of a departmental faculty member.', ARRAY[]::TEXT[], NULL),
    ('SLAV-U 101', 'ELEMENTARY UKRAINIAN I', '6648', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 10:25 AM–11:15 AM', 'WH 114', 'Sofiya Asher', 10, NULL, 'Lecture', '4', 'WOODBURN HALL', ARRAY[]::TEXT[], 'No previous knowledge of Ukrainian required. First semester designed to provide active command of phonology and basic grammatical patterns of Ukrainian.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SLAV-U 101', 'ELEMENTARY UKRAINIAN I', '11511', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 10:25 AM–11:15 AM', 'WB WEB', 'Sofiya Asher', 5, NULL, 'Lecture', '4', 'WOODBURN HALL', ARRAY[]::TEXT[], 'No previous knowledge of Ukrainian required. First semester designed to provide active command of phonology and basic grammatical patterns of Ukrainian.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SLAV-U 201', 'INTERMEDIATE UKRAINIAN I', '8033', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'AC C116', 'Svitlana Melnyk', 2, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'Continuation of work in structure and vocabulary acquisition through study of grammar, drills, and readings. Oral practice and written exercises.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SLAV-U 201', 'INTERMEDIATE UKRAINIAN I', '9966', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'WB WEB', 'Svitlana Melnyk', 2, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'Continuation of work in structure and vocabulary acquisition through study of grammar, drills, and readings. Oral practice and written exercises.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SLAV-U 365', 'TOPICS IN UKRAINIAN LITERATURE, CULTURE, AND LANGUAGE', '34719', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'GA 0009', 'Iryna Voloshyna', 0, NULL, 'Seminar', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Focus on Ukrainian literature, culture, language, linguistics, cinema, etc.; intensive study of an author or authors, a period, a literary or cultural development, linguistic phenomena, etc. Readings and lectures in English.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('SLAV-U 501', 'ELEMENTARY UKRAINIAN I', '9670', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 10:25 AM–11:15 AM', 'WH 114', 'Sofiya Asher', 3, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Introduction to basic structure of contemporary Ukrainian language and culture. No previous knowledge of Ukrainian is required.', ARRAY[]::TEXT[], NULL),
    ('SLAV-U 501', 'ELEMENTARY UKRAINIAN I', '11516', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 10:25 AM–11:15 AM', 'WB WEB', 'Sofiya Asher', 5, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Introduction to basic structure of contemporary Ukrainian language and culture. No previous knowledge of Ukrainian is required.', ARRAY[]::TEXT[], NULL),
    ('SLAV-U 503', 'INTERMEDIATE UKRAINIAN I', '8276', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'AC C116', 'Svitlana Melnyk', 4, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'The course is designed to develop students'' proficiency in all language skills (speaking, reading, writing, and listening) and to get them acquainted with Ukrainian culture. Emphasis is placed on communicative competence - active use of new speech models and structures from the dialogues in course readings, conversation, and listening comprehension.', ARRAY[]::TEXT[], NULL),
    ('SLAV-U 503', 'INTERMEDIATE UKRAINIAN I', '8729', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'WB WEB', 'Svitlana Melnyk', 2, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'The course is designed to develop students'' proficiency in all language skills (speaking, reading, writing, and listening) and to get them acquainted with Ukrainian culture. Emphasis is placed on communicative competence - active use of new speech models and structures from the dialogues in course readings, conversation, and listening comprehension.', ARRAY[]::TEXT[], NULL),
    ('SLAV-X 471', 'UNDERGRADUATE TEACHING INTERNSHIP IN SLAVIC', '36829', 'Closed', NULL, NULL, 'Elizabeth Geballe', 0, NULL, 'Internship', '3', NULL, ARRAY[]::TEXT[], 'Supervised teaching experience in an undergraduate Slavic and East European Languages and Cultures course.', ARRAY[]::TEXT[], NULL),
