    ('SLAV-X 490', 'SUPERVISED INDIVIDUAL READING', '7214', 'Class Status', NULL, NULL, 'George Fowler', 5, NULL, 'Lecture', '1–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Reading, in the original, of materials in field of Slavic studies of particular interest to student.', ARRAY[]::TEXT[], NULL),
    ('SLAV-X 490', 'SUPERVISED INDIVIDUAL READING', '36937', 'Closed', NULL, 'WB WEB', 'Svitlana Melnyk', 0, NULL, 'Lecture', '1–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Reading, in the original, of materials in field of Slavic studies of particular interest to student.', ARRAY[]::TEXT[], NULL),
    ('SLHS-A 100', 'AMERICAN SIGN LANGUAGE LEVEL ONE', '10458', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'LH 008', 'Deborah Gessinger', 0, NULL, 'Lecture', '4', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Introductory sign language course for students with no previous experience with sign language. Builds a good basic vocabulary of signs, teaches fingerspelling, introduces basic aspects of the grammar and the proper use of facial expression in sign language conversation. Includes exposure to deaf culture.', ARRAY['IUB GenEd World Language class'], NULL),
