    ('SLHS-A 100', 'AMERICAN SIGN LANGUAGE LEVEL ONE', '10463', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'WB WEB', 'Joseph Murray', 0, NULL, 'Lecture', '4', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Introductory sign language course for students with no previous experience with sign language. Builds a good basic vocabulary of signs, teaches fingerspelling, introduces basic aspects of the grammar and the proper use of facial expression in sign language conversation. Includes exposure to deaf culture.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SLHS-A 150', 'AMERICAN SIGN LANGUAGE LEVEL TWO', '10262', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 340', 'Dana Demeter', 0, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Continues building receptive and expressive abilities developed in SLHS-A 100. Emphasizes the use of signing space, facial grammar, body postures, fluent fingerspelling, and continued vocabulary development. Introduces more complex grammatical structures. Includes further exposure to deaf culture.', ARRAY['IUB GenEd World Language class'], NULL),
