    ('SLHS-A 200', 'AMERICAN SIGN LANGUAGE LEVEL THREE', '10264', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'BH 340', 'Laura M Smith', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Emphasizes the development of conversational ability. Examines complex grammatical structures, emphasizing the ability to use these structures in conversation. Covers characteristics of the Deaf population and their cultural values.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SLHS-A 200', 'AMERICAN SIGN LANGUAGE LEVEL THREE', '10265', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'BH 340', 'Laura M Smith', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Emphasizes the development of conversational ability. Examines complex grammatical structures, emphasizing the ability to use these structures in conversation. Covers characteristics of the Deaf population and their cultural values.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SLHS-A 200', 'AMERICAN SIGN LANGUAGE LEVEL THREE', '10266', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'BH 340', 'Dana Demeter', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Emphasizes the development of conversational ability. Examines complex grammatical structures, emphasizing the ability to use these structures in conversation. Covers characteristics of the Deaf population and their cultural values.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SLHS-A 200', 'AMERICAN SIGN LANGUAGE LEVEL THREE', '10268', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'LH 008', 'Scott Kochan', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Emphasizes the development of conversational ability. Examines complex grammatical structures, emphasizing the ability to use these structures in conversation. Covers characteristics of the Deaf population and their cultural values.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SLHS-A 200', 'AMERICAN SIGN LANGUAGE LEVEL THREE', '11479', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 340', 'Dana Demeter', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Emphasizes the development of conversational ability. Examines complex grammatical structures, emphasizing the ability to use these structures in conversation. Covers characteristics of the Deaf population and their cultural values.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SLHS-A 200', 'AMERICAN SIGN LANGUAGE LEVEL THREE', '12305', 'Closed', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'LH 008', 'Heath Goodall', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Emphasizes the development of conversational ability. Examines complex grammatical structures, emphasizing the ability to use these structures in conversation. Covers characteristics of the Deaf population and their cultural values.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SLHS-A 250', 'AMERICAN SIGN LANGUAGE LEVEL FOUR', '7698', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'LH 008', 'Deborah Gessinger', 9, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Provides further study of ASL grammar, syntax, and cultural features. Develops competency and fluency in conversational skills. Utilizes vocabulary, grammatical principles, and various discourse features in narratives and presentations in ASL.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SLHS-A 250', 'AMERICAN SIGN LANGUAGE LEVEL FOUR', '12306', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'BH 206', 'Scott Kochan', 5, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Provides further study of ASL grammar, syntax, and cultural features. Develops competency and fluency in conversational skills. Utilizes vocabulary, grammatical principles, and various discourse features in narratives and presentations in ASL.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SLHS-A 250', 'AMERICAN SIGN LANGUAGE LEVEL FOUR', '4866', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'LH 008', 'Rob Loveless', 0, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Provides further study of ASL grammar, syntax, and cultural features. Develops competency and fluency in conversational skills. Utilizes vocabulary, grammatical principles, and various discourse features in narratives and presentations in ASL.', ARRAY['IUB GenEd World Language class'], NULL),
    ('SLHS-A 300', 'AMERICAN SIGN LANGUAGE LEVEL FIVE', '10535', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 340', 'Dana Demeter', 10, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Focuses on continued use of receptive and expressive skills and the acquisition of comprehension skills appropriate to ASL Level Five. Provides an in-depth exploration of major grammatical features, examination of the function of ASL within specific contexts and registers, and opportunities to transition from classroom learning to non-classroom conversational experiences.', ARRAY[]::TEXT[], NULL),
    ('SLHS-A 400', 'DEAF CULTURE', '10453', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'BH 206', 'Heath Goodall', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Provides an overview of American Deaf culture, including cultural identity, core values, group norms, traditions, communication, language, and significant contributions made by Deaf persons. Views and perspectives of and from the Deaf community will be explored along with implications of cultural differences when the Deaf and hearing worlds overlap.', ARRAY['COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('SLHS-A 500', 'ASL LEVEL ONE FOR GRADUATE STUDENTS', '14882', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'LH 008', 'Deborah Gessinger', 1, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Introductory sign language for graduate students with no previous experience. Builds a good basic vocabulary of signs. Teaches finger spelling, introduces basic aspects of the grammar and the proper use of facial expression in sign language conversation. Students are also exposed to deaf culture.', ARRAY[]::TEXT[], NULL),
    ('SLHS-A 550', 'ASL LEVEL TWO FOR GRADUATE STUDENTS', '14883', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 340', 'Dana Demeter', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Continues building receptive and expressive abilities. Puts emphasis on the use of signing space, facial grammar, body postures, fluent finger spelling, and continued vocabulary development. More complex grammatical structures are introduced. Deaf culture component included.', ARRAY[]::TEXT[], NULL),
    ('SLHS-A 600', 'ASL LEVEL THREE FOR GRADUATE STUDENTS', '3449', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'BH 206', 'Laura M Smith', 1, NULL, 'Lecture', '2', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Emphasizes the development of conversational ability. Examines complex grammatical structures, with emphasis on ability to use these structures in conversation. Readings, videos, and discussion cover characteristics of the deaf population and their cultural values.', ARRAY[]::TEXT[], NULL),
    ('SLHS-A 700', 'ASL LEVEL FOUR FOR GRADUATE STUDENTS', '3450', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'LH 008', 'Rob Loveless', 1, NULL, 'Lecture', '2', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Continues to develop knowledge of American sign language and of deaf culture. Students will experience the language outside the classroom through interaction with the deaf community.', ARRAY[]::TEXT[], NULL),
    ('SLHS-G 901', 'ADVANCED RESEARCH', '3023', 'Class Status', NULL, NULL, 'Tessa Bent, Susan Palmiotto', 15, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
