    ('SLHS-G 901', 'ADVANCED RESEARCH', '36701', 'Class Status', NULL, NULL, 'Rita Patel', 5, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('SLHS-G 901', 'ADVANCED RESEARCH', '36702', 'Class Status', NULL, NULL, 'Mini Shrivastav', 5, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('SLHS-G 901', 'ADVANCED RESEARCH', '36703', 'Class Status', NULL, NULL, 'Caroline Spencer', 5, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('SLHS-G 901', 'ADVANCED RESEARCH', '36704', 'Class Status', NULL, NULL, 'Brielle Stark', 4, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 104', 'HUMAN COMMUNICATION AND ITS DISORDERS', '10290', 'Class Status', 'TuThF Tuesday, Thursday, Friday 3:55 PM–4:55 PM', 'WH 120', 'Julie Anderson, Samantha Gustafson', 30, NULL, 'Lecture', '4', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Introduces the scientific foundation of human communication. Mechanisms underlying speaking and listening provide a framework for exploring core topics in speech, language, and hearing sciences. Emphasis given to solving scientific and clinical problems, including how to develop and test hypotheses, analyze data, and investigate how disease and injury affect communication systems.', ARRAY['IUB GenEd N&M credit - Natural Science'], NULL),
    ('SLHS-S 111', 'INTRODUCTION TO PHONETICS FOR SPEECH, LANGUAGE & HEARING SCIENCES', '10282', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'SB 015', 'Tessa Bent', 29, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Provides an introduction to the sounds of human language and the skills needed to describe speech sounds in the articulatory and acoustic domains and transcribe speech using the International Phonetic Alphabet (IPA), including both broad and narrow transcription.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('SLHS-S 201', 'SPEECH ANATOMY AND PHYSIOLOGY', '10269', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'GA 1100', 'Steven Lulich', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Covers anatomy and physiology of the speech mechanism; contemporary views of speech physiology; subsystems of the speech mechanism - respiratory, laryngeal, and supraglottal - integrated with a model of speech production. Includes laboratory experiences.', ARRAY['IUB GenEd N&M credit - Natural Science
COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('SLHS-S 307', 'COGNITIVE AND COMMUNICATIVE ASPECTS OF AGING', '6256', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'GA 1112', 'Shalini Banerjee', 8, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Review of cognitive and communicative changes associated with normal aging as well as with diseases and conditions that are prevalent in the aging population. Includes discussion of methodological issues in research on aging as well as principles for maximizing communication with the elderly population.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('SLHS-S 311', 'INTRODUCTION TO RESEARCH IN SPEECH, LANGUAGE AND HEARING SCIENCES', '4497', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'BH 343', 'Mini Shrivastav', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduction to research methodology in speech and hearing science, both basic and applied. Focuses on basic designs, analyses, and how research informs clinical practice. Course includes discussion of ethics, evaluation of research, and scientific writing.', ARRAY['Class uses IU eTexts'], NULL),
    ('SLHS-S 333', 'CHILDHOOD LANGUAGE', '3692', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'BH 104', 'Ishanti Gangopadhyay', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Develops knowledge of how language is acquired by young children, examines data on what young infants and young children know about language at different ages, and considers the kinds of theories that may explain this data.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('SLHS-S 350', 'SPEECH SCIENCE', '7868', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 006', 'Steven Lulich', 8, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Provides an overview of speech production, including acoustics and physiology, as well as speech perception. The focus is on non-disordered speech in adults with some coverage of development as warranted.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 375', 'HEARING SCIENCE', '6257', 'Closed', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'LH 035', 'Erin Lynch', 0, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Provides an in-depth study of hearing in the normal auditory system. Topics include anatomy and physiology of the ear, anatomy and physiology of the auditory brain, and auditory perception and psychophysics.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 399', 'SENIOR HONORS I: READING AND RESEARCH', '34214', 'Class Status', NULL, NULL, 'Julie Anderson', 2, 'Research', 'Research', '2', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Continuation of work begun in SLHS-S 398. Focuses on the development of students'' individual research projects, with a particular emphasis on research methods and data collection. Group meetings provide for review of general topics related to research, ethics, scholarly writing, and other topics of interest to individual students.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 399', 'SENIOR HONORS I: READING AND RESEARCH', '34212', 'Class Status', 'Tu Tuesday 8:00 AM–9:00 AM', 'BH 229', 'Brielle Stark', 14, 'Lecture', 'Research', '2', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Continuation of work begun in SLHS-S 398. Focuses on the development of students'' individual research projects, with a particular emphasis on research methods and data collection. Group meetings provide for review of general topics related to research, ethics, scholarly writing, and other topics of interest to individual students.', ARRAY[]::TEXT[], NULL),
