    ('SLHS-S 399', 'SENIOR HONORS I: READING AND RESEARCH', '34274', 'Class Status', NULL, NULL, 'Brielle Stark', 2, 'Research', 'Research', '2', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Continuation of work begun in SLHS-S 398. Focuses on the development of students'' individual research projects, with a particular emphasis on research methods and data collection. Group meetings provide for review of general topics related to research, ethics, scholarly writing, and other topics of interest to individual students.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 417', 'SPEECH-LANGUAGE PATHOLOGY ASSISTANT SEMINAR I', '15339', 'Class Status', NULL, 'WB WEB', 'Rachel Gugel, Brooke Burke', 4, NULL, 'Lecture', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Provides the foundation necessary for working as support personnel to assist speech-language pathologists in public school settings. First in a series of two courses required for licensing as an Speech-Language Pathology Assistant.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 417', 'SPEECH-LANGUAGE PATHOLOGY ASSISTANT SEMINAR I', '14401', 'Closed', NULL, NULL, 'Staff', 0, NULL, 'Lecture', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Provides the foundation necessary for working as support personnel to assist speech-language pathologists in public school settings. First in a series of two courses required for licensing as an Speech-Language Pathology Assistant.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 423', 'TOPICAL SEMINAR IN SPEECH, LANGUAGE AND HEARING SCIENCES', '13178', 'Class Status', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'BH 006', 'Ishanti Gangopadhyay', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'In-depth study of specific topics in speech science, language science and hearing science. Topics vary by semester.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 423', 'TOPICAL SEMINAR IN SPEECH, LANGUAGE AND HEARING SCIENCES', '14372', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 318', 'Jennifer Lentz', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'In-depth study of specific topics in speech science, language science and hearing science. Topics vary by semester.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 470', 'ASSESSMENT AND TREATMENT OF HEARING LOSS', '14441', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'LI 028', 'Mini Shrivastav', 10, NULL, 'Lecture', '3', 'WELLS LIBRARY', ARRAY[]::TEXT[], 'Covers basic acoustics, anatomy and physiology of the auditory system with a focus on the applied principles of audiologic evaluation, management, and (re)habilitation options for adult and pediatric populations. It is geared toward upper-level undergraduate students majoring in speech, language, and hearing sciences.', ARRAY['Class uses IU eTexts'], NULL),
    ('SLHS-S 501', 'NEUROLOGICAL AND PHYSIOLOGICAL FOUNDATIONS OF SPEECH-LANGUAGE PATHOLOGY', '3025', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'AH C1021Z', 'Caroline Spencer', 5, NULL, 'Seminar', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This course will introduce students to the anatomical and physiological bases of human communication. Topics will include neuroanatomy and neurophysiology of the central and peripheral nervous systems; neural substrates of speech and language; respiratory, phonatory, articulatory, and swallowing physiology; and current theories of motor control.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 511', 'PHONETICS OF AMERICAN SPEECH', '37313', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'SB 015', 'Tessa Bent', 29, NULL, 'Lecture', '2', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Scientific study of American pronunciation based on International Phonetic Alphabet. Exercises in transcription.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 513', 'SPEECH ANATOMY AND PHYSIOLOGY', '4285', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'GA 1100', 'Steven Lulich', 4, NULL, 'Lecture', '2', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course is designed to provide a functional knowledge of the anatomy (structure) and physiology (function) of the speech mechanism. Topics to be addressed include: respiration, phonation, articulation/resonance nervous system, and audition.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 515', 'TOPICAL SEMINAR IN SPEECH PATHOLOGY', '9860', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'AH C2020', 'Carol Mesa', 6, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SLHS-S 516', 'INTRODUCTION TO AUDIOLOGICAL TESTING', '6601', 'Class Status', 'MW Monday, Wednesday 1:30 PM–2:45 PM', 'AH C3053', 'Erin Lynch', 1, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Rationale and basic procedures in the evaluation of hearing loss. Laboratory exercises.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 517', 'COGNITIVE AND COMMUNICATIVE ASPECTS OF AGING', '6293', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'GA 1112', 'Shalini Banerjee', 5, NULL, 'Lecture', '2', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Review of cognitive and communicative changes associated with normal aging as well as with diseases and conditions that are prevalent in the aging population. Includes discussion of methodological issues in research on aging as well as principles for maximizing communicating with the elderly population.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 519', 'PHYSIOLOGICAL ASSESSMENT OF THE EAR', '10292', 'Class Status', 'MW Monday, Wednesday 3:15 PM–4:30 PM', 'AH C3053', 'Erin Lynch', 2, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This course cover the function of the ear as assessed by physiological methods used in the audiology clinic. The standard measurements of middle ear function include tympanomtry, multi-frequency tympanometry, and power reflectance. The standard measurements of inner ear function include the various types of otoacoustic emissions.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 520', 'PHONOLOGICAL DISORDERS', '6602', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'AH C1021Z', 'Michele Morrisette', 0, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Assessment and treatment of phonological disorders in children; procedures are equally applicable to other populations. Case-based approach to analyses of phonetic, phonemic, syllabic structure in clinical diagnosis and identification of treatment goals. Corresponding treatment methods are evaluated relative to evidence-based practice.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 524', 'SURVEY OF CHILDREN''S LANGUAGE DEVELOPMENT', '3693', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'BH 104', 'Ishanti Gangopadhyay', 2, NULL, 'Lecture', '2', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Theories and research relating to normal development of phonology, syntax, semantics, and pragmatics in children from birth through age four. Investigation of cognition and various environmental factors as contributors to language development. Emphasizes learning of elementary skills in language sample analysis.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 531', 'COGNITIVE-COMMUNICATION DISORDERS IN BRAIN INJURY AND DISEASE', '3026', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', NULL, 'Brielle Stark', 0, NULL, 'Seminar', '3', NULL, ARRAY[]::TEXT[], 'This course reviews disorders of perception, cognition, communication, and behavior associated with brain injury and disease in adults. Procedures and issues pertaining to assessment and treatment in the acute and chronic stages of recovery or across disease progression will also be addressed.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 532', 'LANGUAGE DISORDERS IN CHILDREN', '8698', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'AH C1021Z', 'Carol Mesa', 11, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'The focus of this course will be on the identification, etiology, and clinical treatment of children who are classified having autism spectrum disorder, mental retardation, specific language impairment, and other language disorders.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 540', 'VOICE DISORDERS', '10291', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'AH C1021Z', 'Rita Patel', 24, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This course focuses on facilitating clinical skills related to assessment and management of children and adults with voice disorders. The relevant anatomy and physiology of the vocal mechanism and voice production will be presented. Pathophysiology, causes, prevention, assessment, treatment (behavioral, surgical, and medical) of various voice disorders will be addressed.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 542', 'CARE OF THE PROFESSIONAL VOICE', '8565', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'AH C3051A', 'Rita Patel', 9, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Physiological, psychosocial and occupational aspects of professional voice use. A multi-disciplinary perspective on research and practice in the areas of otolaryngology, social psychology, vocal pedagogy, voice science and communication disorders. Examines historical and current approaches to preventing, assessing, and treating voice breakdown in singers and other professional voice users.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 555', 'MOTOR SPEECH DISORDERS', '8319', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'AH C1021Z', 'Caroline Spencer', 24, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This course will focus on the basic correlates of motor speech disorders in children and adults. Normal development, anatomy, and physiology of the speech production mechanism will be reviewed. Characteristics, pathophysiology, etiology, assessment, and treatment of various motor speech disorders will also be addressed.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 561', 'INTRODUCTION TO CLINICAL PRACTICE & DOCUMENTATION', '3027', 'Class Status', 'Tu Tuesday 11:10 AM–12:10 PM', 'AH C1021Z', 'Carolyn Wade', 16, NULL, 'Lecture', '1', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Current topics related to clinical practice in speech/language pathology.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 567', 'PROFESSIONAL ISSUES AND MEDICAL SPEECH-LANGUAGE PATHOLOGY', '6924', 'Class Status', 'Tu Tuesday 2:20 PM–3:20 PM', 'AH C1023Z', 'Carolyn Wade, Laura Karcher', 24, NULL, 'Lecture', '1', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Current topics related to clinical practice in speech/language pathology.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 570', 'AUDIOLOGY CLINIC PRACTICUM', '3580', 'Class Status', 'F Friday 8:00 AM–9:15 AM', 'AH C3053', 'Sara Rogers', 10, NULL, 'Practicum', '1', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Supervised on-site clinical work in diagnostic and rehabilitative clinical audiology. Intended for students in the first year of the Au. D. program.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 571', 'AUDITORY ANATOMY AND PHYSIOLOGY', '8507', 'Class Status', 'MW Monday, Wednesday 10:00 AM–11:15 AM', 'AH C3051A', 'Gavin Bidelman', 10, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Structure and function of the mammalian auditory system, including aspects of both cellular and systems physiology.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 578', 'AUDIOLOGICAL INSTRUMENTATION AND CALIBRATION', '3028', 'Class Status', 'W Wednesday 8:00 AM–9:40 AM', 'AH C3053', 'Travis Riffle', 10, NULL, 'Seminar', '2', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Fundamentals of acoustics and acoustical measurements including waveform measurements, spectral analysis and noise analysis. Calibration techniques and standards for clinical audiology are also reviewed.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 579', 'PEDIATRIC AUDIOLOGY', '3029', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'AH C3053', 'Samantha Gustafson', 8, NULL, 'Seminar', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Introduction to the assessment and management of communication skills in the pediatric population. Topics include embryologic and physiologic development, auditory disorders, early identification of hearing loss in infants, assessment of hearing and vestibular function in childhood, speech and language development, counseling and management strategies for children with hearing loss.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 580', 'CRITICAL THINKING ABOUT RESEARCH IN COMMUNICATION DISORDERS', '3030', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–1:45 PM', 'AH C1023Z', 'Jennifer Lentz', 4, NULL, 'Seminar', '2', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This course will provide students with the tools and skills to think critically, solve problems, and make ethical and responsible decisions about clinical assessment and treatment. Emphasis will be placed on the role of research in evidence-based practice and the interpretation of scientific literature.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 670', 'CLINICAL PRACTICUM IN AUDIOLOGY 2', '13128', 'Class Status', 'Tu Tuesday 3:00 PM–4:00 PM', 'AH C3053A', 'Jen Bidelman', 8, NULL, 'Practicum', '1–3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Supervised on-site clinical work in diagnostic and rehabilitative clinical audiology. Intended for students in the first year of the Au. D. program.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 671', 'AUDITORY EVOKED POTENTIALS', '34098', 'Class Status', 'Tu Tuesday 8:00 AM–10:30 AM', 'AH C3051A', 'Gavin Bidelman', 8, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Considers the theory and application of auditory evoked potentials, emphasizing brainstem evoked responses for objective audiometry and neurodiagnostic testing.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 673', 'CLINICAL EXTERNSHIP IN AUDIOLOGY 2', '3204', 'Class Status', NULL, NULL, 'Jen Bidelman', 14, NULL, 'Practicum', '5', NULL, ARRAY[]::TEXT[], 'Intensive participation in the clinical activities of community agencies, hospitals or other service providers. Available only to advanced students in audiology program.', ARRAY[]::TEXT[], NULL),
