    ('SLHS-S 683', 'RESEARCH FORUM', '4202', 'Class Status', 'F Friday 12:30 PM–1:30 PM', 'AH C3051', 'Brielle Stark', 15, NULL, 'Lecture', '1–2', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This course includes research presentations by students and faculty in SLHS and guest speakers. Other sessions focus on professional development. The course gives students the opportunity to present their research, to learn about current research in the field, and to acquire skills that will support their professional development.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 685', 'RESEARCH AND ETHICS IN SPEECH, LANGUAGE, AND HEARING SCIENCES', '36558', 'Class Status', 'Tu Tuesday 10:35 AM–1:05 PM', 'HD TBA', 'Julie Anderson', 14, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Selected topics in research design, analysis, and reporting (articles and talks: responsible conduct of research and ethical use of human subjects, and preparation of grant proposals, as appropriate to speech, language, and hearing sciences, and disorders.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 771', 'DIAGNOSTICS AND PATHOLOGIES', '3694', 'Class Status', NULL, 'WB WEB', 'Dana Urbanski', 14, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Examines diagnostic audiology and auditory disorders within the scope of practice of clinical audiology. Attention given to theory, administration, and application of various clinical tests and measures used in assessment and treatment of children and adults.', ARRAY[]::TEXT[], NULL),
    ('SLHS-S 779', 'BUSINESS PRACTICES', '14404', 'Class Status', 'Th Thursday 3:00 PM–5:00 PM', 'AH C3053', 'Jim Urbanski', 23, NULL, 'Lecture', '2', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This course aims to provide students with the tools necessary to create a framework for practicing audiology in a business setting.', ARRAY[]::TEXT[], NULL),
