    ('SLHS-X 498', 'RESEARCH IN SPEECH, LANGUAGE AND HEARING SCIENCES', '34357', 'Class Status', NULL, NULL, 'Travis Riffle', 10, 'Independent Study', 'Research', '0–3', NULL, ARRAY[]::TEXT[], 'Supervised research in an area of speech, language and hearing sciences. A formal research paper or project may be required.', ARRAY[]::TEXT[], NULL),
