    ('SLHS-X 498', 'RESEARCH IN SPEECH, LANGUAGE AND HEARING SCIENCES', '34359', 'Class Status', NULL, NULL, 'Caroline Spencer', 6, 'Independent Study', 'Research', '0–3', NULL, ARRAY[]::TEXT[], 'Supervised research in an area of speech, language and hearing sciences. A formal research paper or project may be required.', ARRAY[]::TEXT[], NULL),
    ('SLHS-X 498', 'RESEARCH IN SPEECH, LANGUAGE AND HEARING SCIENCES', '34360', 'Class Status', NULL, NULL, 'Brielle Stark', 10, 'Independent Study', 'Research', '0–3', NULL, ARRAY[]::TEXT[], 'Supervised research in an area of speech, language and hearing sciences. A formal research paper or project may be required.', ARRAY[]::TEXT[], NULL),
    ('SLST-G 901', 'ADVANCED RESEARCH', '4715', 'Class Status', NULL, NULL, 'Laurent Dekydtspotter', 6, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('SLST-S 112', 'MULTILINGUALISM AND THE BRAIN', '8410', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'WY 005', 'Mike Iverson', 0, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'Explores the problem of fitting several languages into one mind and how the brain adapts to managing several languages. Examines a range of general cognitive issues linked to multilingualism, such as the need to suppress one language in the performance of another, and their effects on the speaker.', ARRAY['IUB GenEd N&M credit - Natural Science
COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('SLST-S 205', 'LANGUAGE AND IDENTITY IN MULTILINGUAL CONTEXTS', '36503', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 3:10 PM–4:00 PM', 'LH 030', 'Debra Friedman', 23, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Explores how individuals use language to (co)construct their own and other''s identities in multilingual contexts and how various facets of identity affect opportunities for language learning and language use. Readings will focus on a wide range of social contexts, languages, and individuals from diverse gender, ethnic, and racial backgrounds.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('SLST-S 213', 'MULTILINGUAL BRAIN AND BEHAVIOR RESEARCH EXPERIENCE', '11343', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 318', 'Mike Iverson', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Provides an introduction to the scientific method for the study of language and training in language data analysis techniques. Introduces knowledge and skills transferable to careers in the social, cognitive, and behavioral sciences through work with data management tools and software used in quantitative linguistic research.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('SLST-S 301', 'INTRODUCTION TO SECOND LANGUAGE ACQUISITION', '4812', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'WH 203', 'Beatrix Burghardt', 13, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Two years of foreign/second language study. Introduces students to contemporary approaches to second language acquisition. Topics include models of second language acquisition, learner variables, the human capacity for language and its availability throughout the lifespan, developmental stages, and effects of instruction. Students will examine samples of learner language and analyze them on their own terms.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('SLST-S 302', 'THE SUCCESSFUL LANGUAGE LEARNER', '8409', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 331', 'Yucel Yilmaz', 15, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Two years of foreign/second language study. Introduces students to the best practices for adult second language learners and to research on learner and learning variables underlying these practices.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('SLST-S 319', 'SPECIAL TOPICS IN SECOND LANGUAGE STUDIES', '29523', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'BH 337', 'Sun-Young Shin', 9, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Topics dealing with cognitive, social, or educational dimensions of second language acquisition or multilingualism.', ARRAY[]::TEXT[], NULL),
    ('SLST-S 532', 'FOUNDATIONS OF SECOND LANGUAGE ACQUISITION', '3500', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'BH 242', 'David Stringer', 18, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduces students to second language acquisition research. Critically examines major hypotheses about the ways in which second languages develop. Discussions will include a range of languages. Models include a variety of approaches: corpora-based, functionalist, generative, processing-based, socio-cultural, and universals of language.', ARRAY[]::TEXT[], NULL),
    ('SLST-S 533', 'SECOND LANGUAGE ACQUISITION RESEARCH DESIGN', '3691', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 016', 'Laurent Dekydtspotter', 6, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SLST-S 536', 'RESEARCH IN SECOND LANGUAGE PEDAGOGICAL CONTEXTS', '5390', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'BH 142', 'Yucel Yilmaz', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SLST-S 632', 'CURRENT RESEARCH IN SECOND LANGUAGE ACQUISITION', '9485', 'Class Status', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'BH 246', 'Rex Sprouse', 12, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This course addresses issues in recent research in second-language acquisition. Examines selected cases illustrating the relation of second-language acquisition studies to linguistic theory. Emphasis on the collection and analysis of acquisition data.', ARRAY[]::TEXT[], NULL),
    ('SLST-S 690', 'INDEPENDENT READINGS IN SECOND LANGUAGE STUDIES', '8739', 'Class Status', NULL, NULL, 'Rex Sprouse', 7, NULL, 'Lecture', '1–4', NULL, ARRAY[]::TEXT[], 'Directed readings in research topics for Second Language Studies.', ARRAY[]::TEXT[], NULL),
    ('SLST-S 800', 'DISSERTATION RESEARCH IN SECOND LANGUAGE STUDIES', '4304', 'Class Status', NULL, NULL, 'Laurent Dekydtspotter', 2, NULL, 'Discussion', '1–12', NULL, ARRAY[]::TEXT[], 'Dissertation research. Arranged.', ARRAY[]::TEXT[], NULL),
    ('SLST-T 100', 'INTENSIVE ENGLISH PROGRAM', '5447', 'Class Status', 'Seven Week - First', NULL, 'Staff', 400, NULL, 'Seminar', '0', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SLST-T 100', 'INTENSIVE ENGLISH PROGRAM', '5448', 'Class Status', 'Seven Week - Second', NULL, 'Staff', 400, NULL, 'Seminar', '0', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SLST-T 131', 'ACADEMIC WRITING FOR MULTILINGUAL STUDENTS: RESEARCH AND INQUIRY', '11248', 'Class Status', 'MWF Monday, Wednesday, Friday 8:00 AM–8:50 AM', 'BH 018', 'Mohammad Khaksar', 9, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Helps multilingual speakers of English develop clarity in academic writing, increase reading comprehension of academic texts, and master revision, peer review, and editing strategies. Focuses on summarizing and paraphrasing, analyzing genre, and increasing focus, support, and logical development. Texts investigate the role of the university in the globalized world.', ARRAY[]::TEXT[], NULL),
    ('SLST-T 131', 'ACADEMIC WRITING FOR MULTILINGUAL STUDENTS: RESEARCH AND INQUIRY', '11249', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'ED 3004', 'Mohammad Khaksar', 4, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Helps multilingual speakers of English develop clarity in academic writing, increase reading comprehension of academic texts, and master revision, peer review, and editing strategies. Focuses on summarizing and paraphrasing, analyzing genre, and increasing focus, support, and logical development. Texts investigate the role of the university in the globalized world.', ARRAY[]::TEXT[], NULL),
