    ('SLST-T 131', 'ACADEMIC WRITING FOR MULTILINGUAL STUDENTS: RESEARCH AND INQUIRY', '11251', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'SY 037', 'Jinman Fu', 3, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Helps multilingual speakers of English develop clarity in academic writing, increase reading comprehension of academic texts, and master revision, peer review, and editing strategies. Focuses on summarizing and paraphrasing, analyzing genre, and increasing focus, support, and logical development. Texts investigate the role of the university in the globalized world.', ARRAY[]::TEXT[], NULL),
