    ('SLST-T 154', 'ACTIVE ACADEMIC LISTENING', '11257', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'BH 209', 'Ruby Zhang', 3, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Helps multilingual speakers of English improve listening skills in academic contexts. Focuses on applying listening strategies, engaging in activities which build vocabulary and promote engagement with information obtained through spoken academic content. Content covers current issues, e.g., food insecurity, business ethics, eco-fashion, and facilitates integration into academic culture.', ARRAY[]::TEXT[], NULL),
    ('SLST-T 154', 'ACTIVE ACADEMIC LISTENING', '12177', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'LH 135', 'Ruby Zhang', 8, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Helps multilingual speakers of English improve listening skills in academic contexts. Focuses on applying listening strategies, engaging in activities which build vocabulary and promote engagement with information obtained through spoken academic content. Content covers current issues, e.g., food insecurity, business ethics, eco-fashion, and facilitates integration into academic culture.', ARRAY[]::TEXT[], NULL),
    ('SLST-T 154', 'ACTIVE ACADEMIC LISTENING', '12178', 'Class Status', 'MWF Monday, Wednesday, Friday 12:45 PM–1:35 PM', 'BH 139', 'Yuri Sibucks', 2, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Helps multilingual speakers of English improve listening skills in academic contexts. Focuses on applying listening strategies, engaging in activities which build vocabulary and promote engagement with information obtained through spoken academic content. Content covers current issues, e.g., food insecurity, business ethics, eco-fashion, and facilitates integration into academic culture.', ARRAY[]::TEXT[], NULL),
    ('SLST-T 155', 'ACADEMIC SPEAKING', '11258', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'GY 1042', 'Eric Lin', 1, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Helps multilingual speakers of English develop clarity and fluency to effectively communicate in spoken academic settings. Focuses on principles governing pronunciation, stress patterns, and expressions that facilitate production, as well as discussion strategies. Materials explore the connection between language, its speakers, and culture, emphasizing features of spoken academic discourse.', ARRAY[]::TEXT[], NULL),
    ('SLST-T 155', 'ACADEMIC SPEAKING', '11634', 'Class Status', 'MWF Monday, Wednesday, Friday 3:10 PM–4:00 PM', 'BH 018', 'Eric Lin', 1, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Helps multilingual speakers of English develop clarity and fluency to effectively communicate in spoken academic settings. Focuses on principles governing pronunciation, stress patterns, and expressions that facilitate production, as well as discussion strategies. Materials explore the connection between language, its speakers, and culture, emphasizing features of spoken academic discourse.', ARRAY[]::TEXT[], NULL),
    ('SLST-T 155', 'ACADEMIC SPEAKING', '11260', 'Closed', 'MWF Monday, Wednesday, Friday 1:55 PM–2:45 PM', 'SY 037', 'Yuri Sibucks', 0, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Helps multilingual speakers of English develop clarity and fluency to effectively communicate in spoken academic settings. Focuses on principles governing pronunciation, stress patterns, and expressions that facilitate production, as well as discussion strategies. Materials explore the connection between language, its speakers, and culture, emphasizing features of spoken academic discourse.', ARRAY[]::TEXT[], NULL),
    ('SLST-T 501', 'ACADEMIC ENGLISH FOR INTERNATIONAL GRADUATE STUDENTS', '36775', 'Closed', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'BH 331', 'Jinman Fu', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Designed to improve spoken or written skills for graduate school. Sections on academic writing (research papers, references, reviews, and critical syntheses) and academic speaking (presentations, discussions, and group work) address a range of academic writing and speaking styles. Credit hours, though counting toward full-time student status, do not count toward the completion of a graduate degree.', ARRAY[]::TEXT[], NULL),
