    ('SLST-T 501', 'ACADEMIC ENGLISH FOR INTERNATIONAL GRADUATE STUDENTS', '37279', 'Closed', NULL, 'BH 719', 'Beatrix Burghardt', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Designed to improve spoken or written skills for graduate school. Sections on academic writing (research papers, references, reviews, and critical syntheses) and academic speaking (presentations, discussions, and group work) address a range of academic writing and speaking styles. Credit hours, though counting toward full-time student status, do not count toward the completion of a graduate degree.', ARRAY[]::TEXT[], NULL),
    ('SLST-T 502', 'COMMUNICATION SKILLS FOR INTERNATIONAL ASSOCIATE INSTRUCTORS', '1880', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'BH 134', 'Beatrix Burghardt', 6, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Develops academic English interactional skills for newly arrived multilingual graduate students preparing to teach undergraduates in the American classroom. Develops speech intelligibility, clarity of expression, and fluency in academic contexts. Increases interactional capacity to meet linguistic and cultural expectations and the ability to monitor performance.', ARRAY[]::TEXT[], NULL),
